mapper.select:
SELECT ird.id, ird.route_code, ird.route_name, ird.equipment_code, ird.equipment_name, ird.sort, ird.creator_id, ird.created_at AS createdAt, ird.updated_at AS updatedAt FROM inspection_route_device ird WHERE ird.route_code = #{routeCode}
AND ird.creator_id = #{creatorId}
ORDER BY ird.sort DESC, ird.id DESC

mapper.update:
UPDATE inspection_route_device
route_code = #{routeCode}, route_name = #{routeName}, equipment_code = #{equipmentCode}, equipment_name = #{equipmentName}, sort = #{sort}, updated_at = #{updatedAt},
WHERE id = #{id}

